    whyus_quote: '\u00ab\u0395\u03af\u03bc\u03b1\u03c3\u03c4\u03b5 \u03ba\u03ac\u03c4\u03b9 \u03c0\u03b5\u03c1\u03b9\u03c3\u03c3\u03cc\u03c4\u03b5\u03c1\u03bf \u03b1\u03c0\u03cc \u03b5\u03ba\u03c0\u03c1\u03cc\u03c3\u03c9\u03c0\u03bf\u03b9&nbsp;\u2014 \u03b5\u03af\u03bc\u03b1\u03c3\u03c4\u03b5 \u03bf \u03b1\u03bc\u03b5\u03c1\u03b9\u03ba\u03b1\u03bd\u03cc\u03c2 \u03b5\u03c4\u03b1\u03af\u03c1\u03bf\u03c2 \u03c3\u03b1\u03c2.\u00bb',
    whyus_body:  '\u0397 EastWest Group International \u03ba\u03b1\u03c4\u03ad\u03c7\u03b5\u03b9 \u03bc\u03bf\u03bd\u03b1\u03b4\u03b9\u03ba\u03ae \u03b8\u03ad\u03c3\u03b7 \u03c3\u03c4\u03b7\u03bd \u03b1\u03bc\u03b5\u03c1\u03b9\u03ba\u03b1\u03bd\u03b9\u03ba\u03ae \u03b1\u03b3\u03bf\u03c1\u03ac: \u03bc\u03b9\u03b1 \u03b5\u03c4\u03b1\u03b9\u03c1\u03b5\u03af\u03b1 \u03bc\u03b5 \u03c0\u03bf\u03bb\u03b9\u03c4\u03b9\u03c3\u03bc\u03b9\u03ba\u03ae \u03b5\u03c5\u03b5\u03bb\u03b9\u03be\u03af\u03b1 \u03b3\u03b9\u03b1 \u03bd\u03b1 \u03ba\u03b1\u03c4\u03b1\u03bd\u03bf\u03b5\u03af \u03c4\u03b7\u03bd \u03c0\u03c1\u03bf\u03ad\u03bb\u03b5\u03c5\u03c3\u03ae \u03c3\u03b1\u03c2 \u03ba\u03b1\u03b9 \u03b5\u03c0\u03b1\u03b3\u03b3\u03b5\u03bb\u03bc\u03b1\u03c4\u03b9\u03ba\u03cc \u03ba\u03cd\u03c1\u03bf\u03c2 \u03b3\u03b9\u03b1 \u03bd\u03b1 \u03b1\u03bd\u03bf\u03af\u03b3\u03b5\u03b9 \u03c0\u03cc\u03c1\u03c4\u03b5\u03c2 \u03b5\u03b4\u03ce. \u03a3\u03c5\u03bd\u03b4\u03c5\u03ac\u03b6\u03bf\u03c5\u03bc\u03b5 \u03c0\u03c1\u03b1\u03ba\u03c4\u03b9\u03ba\u03ae \u03b1\u03bd\u03ac\u03c0\u03c4\u03c5\u03be\u03b7 \u03b5\u03c0\u03b9\u03c7\u03b5\u03b9\u03c1\u03ae\u03c3\u03b5\u03c9\u03bd \u03bc\u03b5 \u03b2\u03b1\u03b8\u03b9\u03ac \u03c0\u03b5\u03c1\u03b9\u03c6\u03b5\u03c1\u03b5\u03b9\u03b1\u03ba\u03ae \u03b3\u03bd\u03ce\u03c3\u03b7, \u03bb\u03b5\u03b9\u03c4\u03bf\u03c5\u03c1\u03b3\u03ce\u03bd\u03c4\u03b1\u03c2 \u03c9\u03c2 \u03b1\u03bb\u03b7\u03b8\u03b9\u03bd\u03ae \u03b5\u03c0\u03ad\u03ba\u03c4\u03b1\u03c3\u03b7 \u03c4\u03b7\u03c2 \u03bf\u03bc\u03ac\u03b4\u03b1\u03c2 \u03c3\u03b1\u03c2.',
    whyus_label: '\u03a4\u03b9 \u03bc\u03b1\u03c2 \u03be\u03b5\u03c7\u03c9\u03c1\u03af\u03b6\u03b5\u03b9',
    diff1: '\u039c\u03cc\u03bd\u03b9\u03bc\u03b7 \u03c0\u03b1\u03c1\u03bf\u03c5\u03c3\u03af\u03b1 \u03c3\u03c4\u03b7\u03bd \u03b1\u03bc\u03b5\u03c1\u03b9\u03ba\u03b1\u03bd\u03b9\u03ba\u03ae \u03b1\u03b3\u03bf\u03c1\u03ac \u03ba\u03b1\u03b9 \u03b5\u03c0\u03b1\u03b3\u03b3\u03b5\u03bb\u03bc\u03b1\u03c4\u03b9\u03ba\u03cc \u03ba\u03cd\u03c1\u03bf\u03c2',
    diff2: '\u03a0\u03bf\u03bb\u03cd\u03b3\u03bb\u03c9\u03c3\u03c3\u03b7 \u03bf\u03bc\u03ac\u03b4\u03b1: \u03b1\u03b3\u03b3\u03bb\u03b9\u03ba\u03ac, \u03c1\u03c9\u03c3\u03b9\u03ba\u03ac, \u03b9\u03c3\u03c0\u03b1\u03bd\u03b9\u03ba\u03ac, \u03b3\u03b1\u03bb\u03bb\u03b9\u03ba\u03ac, \u03b9\u03c4\u03b1\u03bb\u03b9\u03ba\u03ac',
    diff3: '\u039c\u03b7\u03c7\u03b1\u03bd\u03bf\u03bb\u03bf\u03b3\u03b9\u03ba\u03cc \u03ba\u03b1\u03b9 \u03c4\u03b5\u03c7\u03bd\u03b9\u03ba\u03cc \u03c5\u03c0\u03cc\u03b2\u03b1\u03b8\u03c1\u03bf \u2014 \u03ba\u03b1\u03c4\u03b1\u03bd\u03bf\u03bf\u03cd\u03bc\u03b5 \u03c4\u03bf \u03c0\u03c1\u03bf\u03ca\u03cc\u03bd \u03c3\u03b1\u03c2',
    diff4: '\u0391\u03c0\u03bf\u03b4\u03b5\u03b4\u03b5\u03b9\u03b3\u03bc\u03ad\u03bd\u03b7 \u03b5\u03bc\u03c0\u03b5\u03b9\u03c1\u03af\u03b1 B2B \u03c0\u03c9\u03bb\u03ae\u03c3\u03b5\u03c9\u03bd \u03ba\u03b1\u03b9 \u03ba\u03bb\u03b5\u03b9\u03c3\u03af\u03bc\u03b1\u03c4\u03bf\u03c2 \u03c3\u03c5\u03bc\u03c6\u03c9\u03bd\u03b9\u03ce\u03bd',
    diff5: '\u0392\u03b1\u03b8\u03b9\u03ac \u03c0\u03bf\u03bb\u03b9\u03c4\u03b9\u03c3\u03bc\u03b9\u03ba\u03ae \u03b5\u03c5\u03b1\u03b9\u03c3\u03b8\u03b7\u03c3\u03af\u03b1 \u03c0\u03bf\u03c5 \u03b3\u03b5\u03c6\u03c5\u03c1\u03ce\u03bd\u03b5\u03b9 \u03b1\u03bd\u03b1\u03c4\u03bf\u03bb\u03b9\u03ba\u03ad\u03c2 \u03ba\u03b1\u03b9 \u03b4\u03c5\u03c4\u03b9\u03ba\u03ad\u03c2 \u03b5\u03c0\u03b9\u03c7\u03b5\u03b9\u03c1\u03b7\u03bc\u03b1\u03c4\u03b9\u03ba\u03ad\u03c2 \u03c0\u03c1\u03b1\u03ba\u03c4\u03b9\u03ba\u03ad\u03c2',
    diff6: '\u0394\u03af\u03ba\u03c4\u03c5\u03bf \u03c3\u03c4\u03bf\u03bd \u03c4\u03bf\u03bc\u03ad\u03b1 \u03c4\u03b5\u03c7\u03bd\u03bf\u03bb\u03bf\u03b3\u03af\u03b1\u03c2, \u03b5\u03bd\u03ad\u03c1\u03b3\u03b5\u03b9\u03b1\u03c2, fintech \u03ba\u03b1\u03b9 \u03b2\u03b9\u03bf\u03bc\u03b7\u03c7\u03b1\u03bd\u03af\u03b1\u03c2',
    diff7: '\u0395\u03bd\u03b5\u03c1\u03b3\u03ae \u03b1\u03bd\u03b1\u03b6\u03ae\u03c4\u03b7\u03c3\u03b7 \u03b2\u03b9\u03ce\u03c3\u03b9\u03bc\u03c9\u03bd \u03c0\u03c1\u03bf\u03ca\u03cc\u03bd\u03c4\u03c9\u03bd \u2014 \u03b4\u03b5\u03bd \u03c3\u03c5\u03bc\u03b2\u03bf\u03c5\u03bb\u03b5\u03cd\u03bf\u03c5\u03bc\u03b5 \u03bc\u03cc\u03bd\u03bf, \u03c6\u03ad\u03c1\u03bd\u03bf\u03c5\u03bc\u03b5 \u03b5\u03c5\u03c1\u03c9\u03c0\u03b1\u03ca\u03ba\u03ad\u03c2 \u03ba\u03b1\u03b9\u03bd\u03bf\u03c4\u03bf\u03bc\u03af\u03b5\u03c2 \u03c3\u03c4\u03b7\u03bd \u03b1\u03b3\u03bf\u03c1\u03ac',
    diff8: '\u03a3\u03c7\u03ad\u03c3\u03b5\u03b9\u03c2 \u03c0\u03bf\u03c5 \u043e\u0445\u0432\u0430\u0442\u044b\u0432\u0430\u044e\u0442 \u0394\u03c5\u03c4\u03b9\u03ba\u03ae \u0395\u03c5\u03c1\u03ce\u03c0\u03b7, \u039c\u03b5\u03c3\u03cc\u03b3\u03b5\u03b9\u03bf \u03ba\u03b1\u03b9 \u03c4\u03bf\u03bd \u03b5\u03c5\u03c1\u03cd\u03c4\u03b5\u03c1\u03bf \u03b5\u03c5\u03c1\u03b1\u03c3\u03b9\u03b1\u03c4\u03b9\u03ba\u03cc \u03b4\u03b9\u03ac\u03b4\u03c1\u03bf\u03bc\u03bf',

