// ============================================================
//  LANGUAGE LOGIC
// ============================================================
let currentLang = localStorage.getItem('ewg_lang') || 'en';

function applyLanguage(lang) {
  currentLang = lang;
  localStorage.setItem('ewg_lang', lang);

  // Update <html lang>
  document.documentElement.lang = lang;

  // data-i18n — textContent
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.dataset.i18n;
    if (translations[lang][key] !== undefined) {
      el.textContent = translations[lang][key];
    }
  });

  // data-i18n-html — innerHTML (for elements containing HTML tags/entities)
  document.querySelectorAll('[data-i18n-html]').forEach(el => {
    const key = el.dataset.i18nHtml;
    if (translations[lang][key] !== undefined) {
      el.innerHTML = translations[lang][key];
    }
  });

  // data-i18n-placeholder — placeholder attribute
  document.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
    const key = el.dataset.i18nPlaceholder;
    if (translations[lang][key] !== undefined) {
      el.placeholder = translations[lang][key];
    }
  });

  // Update toggle active state
  document.getElementById('lang-en').classList.toggle('lang-opt--active', lang === 'en');
  document.getElementById('lang-ru').classList.toggle('lang-opt--active', lang === 'ru');
  document.getElementById('lang-gr').classList.toggle('lang-opt--active', lang === 'gr');
}

document.getElementById('langToggle').addEventListener('click', (e) => {
  const clicked = e.target.closest('.lang-opt');
  if (clicked) {
    if (clicked.id === 'lang-en') applyLanguage('en');
    else if (clicked.id === 'lang-ru') applyLanguage('ru');
    else if (clicked.id === 'lang-gr') applyLanguage('gr');
  } else {
    const cycle = { en: 'ru', ru: 'gr', gr: 'en' };
    applyLanguage(cycle[currentLang] || 'en');
  }
});

// Apply on page load
applyLanguage(currentLang);

// ============================================================
//  STICKY NAV SHADOW
// ============================================================
const nav = document.getElementById('siteNav');
const onScroll = () => {
  nav.classList.toggle('scrolled', window.scrollY > 10);
};
window.addEventListener('scroll', onScroll, { passive: true });

// ============================================================
//  MOBILE MENU
// ============================================================
document.querySelectorAll('.mobile-menu a').forEach(link => {
  link.addEventListener('click', () => {
    document.getElementById('menu-toggle').checked = false;
  });
});

window.addEventListener('resize', () => {
  if (window.innerWidth > 768) {
    document.getElementById('menu-toggle').checked = false;
  }
});
